.tooltip {
  position: absolute;
  top: 0;
  left: 0;
  pointer-events: none;
  opacity: 0;
}

.fixed {
  position: fixed;
}

.arrow {
  position: absolute;
  background: inherit;
  z-index: -1;
  -webkit-backface-visibility: hidden;
  backface-visibility: hidden;
}

.content {
  position: relative;
  z-index: 1;
}

.noArrow {
  display: none;
}

.clickable {
  pointer-events: auto;
}

.show {
  opacity: var(--rt-opacity);
  transition: opacity var(--rt-transition-show-delay) ease-out;
  will-change: opacity;
}

.closing {
  opacity: 0;
  transition: opacity var(--rt-transition-closing-delay) ease-in;
  will-change: opacity;
}

